#include<bits/stdc++.h>
using namespace std;

int main(){
    int a[10001],n,t[10001],len=0,maxx;
    cin>>n;
    for(int i=1;i<=n;i++){
        cin>>a[i];
        len=max(len,a[i]);
        t[a[i]]++;
    }
    for(int i=1;i<=len;i++) maxx=max(t[i],maxx);
    cout<<maxx;
    return 0;
}
